   223→  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
   224→    return Http::FilterDataStatus::Continue;
   225→  }
   226→  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
   227→    return Http::FilterTrailersStatus::Continue;
   228→  }
   229→  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
   230→    return Http::FilterMetadataStatus::Continue;
   231→  }
   232→  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;
   233→
