   257→  bool addMetadata(StructMap&, const std::string&, const std::string&, std::string, ValueType,
   258→                   ValueEncode, HeaderDirection direction) const;
   259→  void applyKeyValue(std::string&&, const Rule&, const KeyValuePair&, StructMap&,
   260→                     HeaderDirection direction);
   261→  const std::string& decideNamespace(const std::string& nspace) const;
   262→  const Config* getConfig() const;
