    10→FilterConfig::FilterConfig(CredentialInjectorSharedPtr credential_injector, bool overwrite,
    11→                           bool allow_request_without_credential, const std::string& stats_prefix,
    12→                           Stats::Scope& scope)
    13→    : injector_(credential_injector), overwrite_(overwrite),
    14→      allow_request_without_credential_(allow_request_without_credential),
    15→      stats_(generateStats(stats_prefix, scope)) {}
    16→
    17→// Inject configured credential to the HTTP request header.
    18→// return true if successful
    19→bool FilterConfig::injectCredential(Envoy::Http::RequestHeaderMap& headers) {
    20→  absl::Status status = injector_->inject(headers, overwrite_);
    21→
    22→  // If the credential already exists in the header and overwrite is false,
    23→  // increase the counter and continue processing the request.
    24→  if (absl::IsAlreadyExists(status)) {
    25→    ASSERT(!overwrite_); // overwrite should be false if AlreadyExists is returned
    26→    ENVOY_LOG(trace, "Credential already exists in the header");
    27→    stats_.already_exists_.inc();
    28→    // continue processing the request if credential already exists in the header
