    16→    const envoy::extensions::filters::http::credential_injector::v3::CredentialInjector&
    17→        proto_config,
    18→    const std::string& stats_prefix, Server::Configuration::ServerFactoryContext& context,
    19→    Stats::Scope& scope, Init::Manager& init_manager) const {
    20→
    21→  // Find the credential injector factory.
    22→  auto* config_factory = Envoy::Config::Utility::getFactory<NamedCredentialInjectorConfigFactory>(
    23→      proto_config.credential());
    24→  if (config_factory == nullptr) {
    25→    return absl::InvalidArgumentError(fmt::format(
    26→        "Didn't find a registered implementation for '{}' with type URL: '{}'",
    27→        proto_config.credential().name(),
    28→        Envoy::Config::Utility::getFactoryType(proto_config.credential().typed_config())));
    29→  }
    30→
    31→  // create the credential injector
    32→  ProtobufTypes::MessagePtr message = Config::Utility::translateAnyToFactoryConfig(
    33→      proto_config.credential().typed_config(), context.messageValidationVisitor(),
    34→      *config_factory);
    35→  CredentialInjectorSharedPtr credential_injector =
    36→      config_factory->createCredentialInjectorFromProto(
    37→          *message, stats_prefix + "credential_injector.", context, init_manager);
    38→
    39→  FilterConfigSharedPtr config =
    40→      std::make_shared<FilterConfig>(std::move(credential_injector), proto_config.overwrite(),
    41→                                     proto_config.allow_request_without_credential(),
    42→                                     stats_prefix + "credential_injector.", scope);
    43→  return [config](Envoy::Http::FilterChainFactoryCallbacks& callbacks) -> void {
    44→    callbacks.addStreamDecoderFilter(std::make_shared<CredentialInjectorFilter>(config));
    45→  };
    46→}
