    58→Envoy::Http::FilterFactoryCb
    59→CredentialInjectorFilterFactory::createFilterFactoryFromProtoWithServerContextTyped(
    60→    const envoy::extensions::filters::http::credential_injector::v3::CredentialInjector&
    61→        proto_config,
    62→    const std::string& stats_prefix, Server::Configuration::ServerFactoryContext& context) {
    63→  auto result = createFilterFactoryFromProtoHelper(proto_config, stats_prefix, context,
    64→                                                   context.scope(), context.initManager());
    65→  if (!result.ok()) {
    66→    ExceptionUtil::throwEnvoyException(std::string(result.status().message()));
    67→  }
    68→  return std::move(result.value());
    69→}
