namespace CustomHeaderInjection {

FilterConfig::FilterConfig(
    const envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection&
        config)
    : request_headers_(config.request_headers().begin(), config.request_headers().end()),
      response_headers_(config.response_headers().begin(), config.response_headers().end()) {
  ENVOY_LOG(debug, "Custom Header Injection filter initialized with {} request headers and {} "
                   "response headers",
            request_headers_.size(), response_headers_.size());
}

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(FilterConfigSharedPtr config)
    : config_(std::move(config)) {}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
                                                                     bool) {
  // Inject request headers
  for (const auto& [key, value] : config_->requestHeaders()) {
    headers.setReference(Http::LowerCaseString(key), value);
    ENVOY_LOG(trace, "Injected request header: {} = {}", key, value);
  }

  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
                                                                     bool) {
  // Inject response headers
  for (const auto& [key, value] : config_->responseHeaders()) {
    headers.setReference(Http::LowerCaseString(key), value);
    ENVOY_LOG(trace, "Injected response header: {} = {}", key, value);
  }

  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

