namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
protected:
  NiceMock<Envoy::Http::MockStreamDecoderFilterCallbacks> decoder_filter_callbacks_;
  NiceMock<Envoy::Http::MockStreamEncoderFilterCallbacks> encoder_filter_callbacks_;
};

TEST_F(CustomHeaderInjectionFilterTest, InjectRequestHeaders) {
  // Create a config with request headers
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection proto_config;
  proto_config.mutable_request_headers()->insert({"x-custom-request", "request-value"});
  proto_config.mutable_request_headers()->insert({"x-another-header", "another-value"});

  auto config = std::make_shared<FilterConfig>(proto_config);
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);
  filter->setDecoderFilterCallbacks(decoder_filter_callbacks_);

  // Create request headers
  Envoy::Http::TestRequestHeaderMapImpl request_headers{};

  // Process headers
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));

  // Verify headers were injected
  EXPECT_EQ("request-value", request_headers.get_("x-custom-request"));
  EXPECT_EQ("another-value", request_headers.get_("x-another-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectResponseHeaders) {
  // Create a config with response headers
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection proto_config;
  proto_config.mutable_response_headers()->insert({"x-custom-response", "response-value"});
  proto_config.mutable_response_headers()->insert({"x-response-header", "response-val"});

  auto config = std::make_shared<FilterConfig>(proto_config);
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);
  filter->setEncoderFilterCallbacks(encoder_filter_callbacks_);

  // Create response headers
  Envoy::Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};

  // Process headers
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->encodeHeaders(response_headers, true));

  // Verify headers were injected
  EXPECT_EQ("response-value", response_headers.get_("x-custom-response"));
  EXPECT_EQ("response-val", response_headers.get_("x-response-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectBothRequestAndResponseHeaders) {
  // Create a config with both request and response headers
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection proto_config;
  proto_config.mutable_request_headers()->insert({"x-request-header", "request-val"});
  proto_config.mutable_response_headers()->insert({"x-response-header", "response-val"});

  auto config = std::make_shared<FilterConfig>(proto_config);
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);
  filter->setDecoderFilterCallbacks(decoder_filter_callbacks_);
  filter->setEncoderFilterCallbacks(encoder_filter_callbacks_);

  // Test request header injection
  Envoy::Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));
  EXPECT_EQ("request-val", request_headers.get_("x-request-header"));

  // Test response header injection
  Envoy::Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->encodeHeaders(response_headers, true));
  EXPECT_EQ("response-val", response_headers.get_("x-response-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, NoHeadersConfigured) {
  // Create a config with no headers
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection proto_config;

  auto config = std::make_shared<FilterConfig>(proto_config);
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);
  filter->setDecoderFilterCallbacks(decoder_filter_callbacks_);
  filter->setEncoderFilterCallbacks(encoder_filter_callbacks_);

  // Test request headers
  Envoy::Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));

  // Test response headers
  Envoy::Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->encodeHeaders(response_headers, true));
}

TEST_F(CustomHeaderInjectionFilterTest, OverwriteExistingHeaders) {
  // Create a config with request headers
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection proto_config;
  proto_config.mutable_request_headers()->insert({"x-existing", "new-value"});

  auto config = std::make_shared<FilterConfig>(proto_config);
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);
  filter->setDecoderFilterCallbacks(decoder_filter_callbacks_);

  // Create request headers with an existing header
  Envoy::Http::TestRequestHeaderMapImpl request_headers{{"x-existing", "old-value"}};

  // Process headers
  EXPECT_EQ(Envoy::Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));

  // Verify header was overwritten
  EXPECT_EQ("new-value", request_headers.get_("x-existing"));
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

